import re
from dataclasses import dataclass
from typing import Optional

@dataclass
class EvaluationContext:
    """All information available at evaluation time."""
    text: str                       # input or output text
    scope: PolicyScope              # which stage we are at
    session_id: str
    user_id: str
    category_scores: dict[str, float] = field(default_factory=dict)
    pii_found: list[str] = field(default_factory=list)
    topic_drift_score: float = 1.0  # 1.0 = on-topic, 0.0 = fully off-topic
    custom_signals: dict[str, Any] = field(default_factory=dict)

@dataclass
class EnforcementDecision:
    action: EnforcementAction
    rule_id: str
    rule_name: str
    reason: str
    message_override: Optional[str] = None

def evaluate_condition(condition: dict[str, Any], ctx: EvaluationContext) -> bool:
    """Return True if the condition matches the context."""
    ctype = condition["type"]
    if ctype == "category":
        cat = condition["category"]
        min_score = condition.get("confidence_min", 0.5)
        return ctx.category_scores.get(cat, 0.0) >= min_score
    if ctype == "pii_present":
        return len(ctx.pii_found) > 0
    if ctype == "topic_drift":
        threshold = condition.get("threshold", 0.30)
        return ctx.topic_drift_score < threshold
    if ctype == "regex":
        pattern = re.compile(condition["pattern"], re.I)
        return bool(pattern.search(ctx.text))
    if ctype == "custom_signal":
        key = condition["key"]
        min_val = condition.get("min", 0)
        return ctx.custom_signals.get(key, 0) >= min_val
    if ctype == "and":
        return all(evaluate_condition(c, ctx) for c in condition["conditions"])
    if ctype == "or":
        return any(evaluate_condition(c, ctx) for c in condition["conditions"])
    if ctype == "not":
        return not evaluate_condition(condition["condition"], ctx)
    raise ValueError(f"Unknown condition type: {ctype!r}")

def evaluate_rules(
    ctx: EvaluationContext,
    rules: list[PolicyRule],
    conflict_resolution: ConflictResolution = ConflictResolution.MOST_RESTRICTIVE,
) -> EnforcementDecision:
    """Evaluate all applicable rules and return the winning decision."""
    matching: list[PolicyRule] = []
    for rule in rules:
        if rule.scope not in (ctx.scope, PolicyScope.BOTH):
            continue
        if evaluate_condition(rule.condition, ctx):
            matching.append(rule)
            if conflict_resolution == ConflictResolution.FIRST_MATCH:
                break   # stop at first match

    if not matching:
        return EnforcementDecision(
            action=EnforcementAction.ALLOW,
            rule_id="default", rule_name="default allow",
            reason="no matching rules",
        )

    if conflict_resolution == ConflictResolution.MOST_RESTRICTIVE:
        winner = max(matching, key=lambda r: ACTION_SEVERITY[r.action])
    else:
        winner = matching[0]

    return EnforcementDecision(
        action=winner.action,
        rule_id=winner.id,
        rule_name=winner.name,
        reason=f"matched rule {winner.id}",
        message_override=winner.message_override,
    )

import logging, hashlib

logger = logging.getLogger("policy_enforcement")

DEFAULT_BLOCK_MESSAGE = (
    "I'm not able to help with that request. "
    "Please review our usage policy or contact support."
)

def _hash(s: str) -> str:
    return hashlib.sha256(s.encode()).hexdigest()[:12]

def dispatch_action(
    decision: EnforcementDecision,
    original_text: str,
    ctx: EvaluationContext,
    redact_fn=None,          # callable(text) -> redacted_text
    review_queue=None,       # callable(ctx, decision) -> None
    alert_fn=None,           # callable(ctx, decision) -> None
) -> tuple[bool, str]:
    """
    Execute the enforcement action.
    Returns (delivered: bool, output_text: str).
    """
    action = decision.action

    # Always log every decision
    logger.info("policy_decision", extra={
        "action": action, "rule_id": decision.rule_id,
        "session": ctx.session_id, "user": _hash(ctx.user_id),
        "scope": ctx.scope, "reason": decision.reason,
    })

    if action == EnforcementAction.ALLOW:
        return True, original_text

    if action == EnforcementAction.BLOCK:
        msg = decision.message_override or DEFAULT_BLOCK_MESSAGE
        return False, msg

    if action == EnforcementAction.REDACT:
        if redact_fn:
            redacted = redact_fn(original_text)
        else:
            # Simple fallback: replace known PII with placeholders
            redacted = original_text
            for pii_type in ctx.pii_found:
                redacted = redacted.replace(pii_type, "[REDACTED]")
        return True, redacted

    if action == EnforcementAction.WARN:
        if review_queue:
            review_queue(ctx, decision)
        return True, original_text   # deliver as-is, flag async

    if action == EnforcementAction.RATE_LIMIT:
        # Rate limiting handled upstream; here we just log and allow
        logger.warning("rate_limit_applied", extra={
            "user": _hash(ctx.user_id), "rule": decision.rule_id,
        })
        return True, original_text

    if action == EnforcementAction.QUARANTINE:
        if review_queue:
            review_queue(ctx, decision)
        return False, "Your request is being reviewed. We'll follow up shortly."

    if action == EnforcementAction.ESCALATE:
        if alert_fn:
            alert_fn(ctx, decision)
        if review_queue:
            review_queue(ctx, decision)
        return False, "This request has been flagged and escalated for review."

    raise ValueError(f"Unknown action: {action!r}")
